const TypePredicateParameterNameKinds = new Set(['Identifier', 'ThisKeyword', 'ThisType']);
export function isTypePredicateParameterName(node: KSNode): node is KSTypePredicateParameterName {
  return TypePredicateParameterNameKinds.has(node.kind);
}
